// Process deals data
const dealsData = $input.item(0).json.results || [];

const totalDeals = dealsData.length;
const totalValue = dealsData.reduce((sum, deal) => sum + (parseFloat(deal.properties.amount) || 0), 0);
const avgDealSize = totalDeals > 0 ? totalValue / totalDeals : 0;

// Group by stage
const byStage = dealsData.reduce((acc, deal) => {
  const stage = deal.properties.dealstage;
  acc[stage] = (acc[stage] || 0) + 1;
  return acc;
}, {});

return {
  totalDeals,
  totalValue,
  avgDealSize,
  byStage
};

// Process leads data
const leadsData = $input.item(0).json.results || [];

const totalLeads = leadsData.length;

// Group by lifecycle stage
const byLifecycle = leadsData.reduce((acc, lead) => {
  const stage = lead.properties.lifecyclestage || 'unknown';
  acc[stage] = (acc[stage] || 0) + 1;
  return acc;
}, {});

// Group by lead status
const byStatus = leadsData.reduce((acc, lead) => {
  const status = lead.properties.hs_lead_status || 'unqualified';
  acc[status] = (acc[status] || 0) + 1;
  return acc;
}, {});

return {
  totalLeads,
  byLifecycle,
  byStatus
};

// Process closed deals
const closedData = $input.item(0).json.results || [];

const totalClosed = closedData.length;
const revenue = closedData.reduce((sum, deal) => sum + (parseFloat(deal.properties.amount) || 0), 0);

return {
  totalClosed,
  revenue
};

// Get all metric inputs
const dealMetrics = $input.item(0).json;
const leadMetrics = $input.item(1).json;
const closedMetrics = $input.item(2).json;

// Format as email body
const emailBody = `
<h2>📊 Daily Sales Metrics - ${new Date().toLocaleDateString()}</h2>

<h3>💰 Revenue</h3>
<ul>
  <li><strong>Deals Closed:</strong> ${closedMetrics.totalClosed}</li>
  <li><strong>Revenue Generated:</strong> $${closedMetrics.revenue.toLocaleString()}</li>
</ul>

<h3>🤝 New Deals</h3>
<ul>
  <li><strong>Total New Deals:</strong> ${dealMetrics.totalDeals}</li>
  <li><strong>Total Pipeline Value:</strong> $${dealMetrics.totalValue.toLocaleString()}</li>
  <li><strong>Average Deal Size:</strong> $${dealMetrics.avgDealSize.toFixed(2)}</li>
</ul>

<h4>Breakdown by Stage:</h4>
<ul>
${Object.entries(dealMetrics.byStage).map(([stage, count]) => 
  `  <li>${stage}: ${count} deals</li>`
).join('\n')}
</ul>

<h3>👥 New Leads</h3>
<ul>
  <li><strong>Total New Leads:</strong> ${leadMetrics.totalLeads}</li>
</ul>

<h4>Breakdown by Lifecycle:</h4>
<ul>
${Object.entries(leadMetrics.byLifecycle).map(([stage, count]) => 
  `  <li>${stage}: ${count} leads</li>`
).join('\n')}
</ul>

<h4>Breakdown by Status:</h4>
<ul>
${Object.entries(leadMetrics.byStatus).map(([status, count]) => 
  `  <li>${status}: ${count} leads</li>`
).join('\n')}
</ul>

<hr>
<p><em>Generated automatically by n8n at ${new Date().toLocaleTimeString()}</em></p>
`;

return {
  subject: `Daily Sales Digest - ${new Date().toLocaleDateString()}`,
  body: emailBody,
  metrics: {
    deals: dealMetrics,
    leads: leadMetrics,
    closed: closedMetrics
  }
};

